static inline int csilc_enc_AccessLevel(csilc_buf *b, const AccessLevel *v);
static inline int csilc_dec_AccessLevel(const csilc_value *src, CsilCodecArena *a, AccessLevel *out);
static inline int csilc_enc_GranteeType(csilc_buf *b, const GranteeType *v);
static inline int csilc_dec_GranteeType(const csilc_value *src, CsilCodecArena *a, GranteeType *out);
static inline int csilc_enc_ResourceType(csilc_buf *b, const ResourceType *v);
